INSERT INTO "news" ("id","league_id","team_id","type","headline","body","game_week","created_at") VALUES('7032ce23-526d-4440-9cca-d38bcaae9160','7a82b469-d4db-4ee6-b730-2ec85a68122d','44e88dfe-6000-4d3e-a6c5-980eec6be216','manager_arrival','Nová éra v Spůle: Zdeněk Jungvirt u kormidla','V Spůle to žije — Zdeněk Jungvirt převzal tým FK Löffler Spůle. „Chceme hrát dobrý fotbal," řekl po svém jmenování. Na soupisku se dostal 18 hráčů, tahouny by měli být Jan Robl (MID, 35), Lukáš Šandera (MID, 33), Tomáš Novotný (DEF, 33).',NULL,'2026-03-29 09:17:52');
INSERT INTO "news" ("id","league_id","team_id","type","headline","body","game_week","created_at") VALUES('6c932422-f3f3-4c5d-aee2-2f4d0abf8ff2','7a82b469-d4db-4ee6-b730-2ec85a68122d','04da5b26-f848-48cb-b5c8-731a2f65811c','manager_arrival','FK Rohde Čkyně má nového trenéra: Rody!','Rody přebírá vedení FK Rohde Čkyně z Čkyně. V kádru je 20 hráčů, oporami by měli být Ondřej Marek (GK, 43), Lukáš Havel (DEF, 41), Lukáš Grill (FWD, 40). Fanoušci jsou zvědaví, co přinese nová éra.',NULL,'2026-03-29 09:35:06');
