INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(1,'goal','GÓÓÓL! {player} to tam napálil! {crowd_reaction}','["epic"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(2,'goal','{player} zakončuje a je to tam! {minute}. minuta!','["normal"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(3,'goal','Parádní akce! {player} si to obhodil a uklidil to k tyči!','["epic"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(4,'goal','{player} hlavou po rohu — brankář jen koukal!','["header"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(5,'goal','No tak {player} se trefil. Upřímně, ani on tomu nevěří.','["funny"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(6,'goal','{player} střílí zpoza vápna a míč se odráží do branky. Počítá se!','["lucky"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(7,'goal','Gól! {player} proměňuje penaltu. Brankář skákal doprava, míč šel doleva.','["penalty"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(8,'goal','{player} to tam doslova dotlačil. Nebyla to krása, ale je to gól.','["ugly"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(9,'goal','Bomba od {player}! To se muselo slyšet až v hospodě!','["epic"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(10,'goal','{player} si naběhl za obranu a s přehledem skóruje.','["normal"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(11,'goal','Brankář pustil míč pod rukama a {player} to dopíchl do prázdné.','["gk_error"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(12,'goal','{player} to zkusil z půlky a ono to spadlo! Gól roku okresu!','["epic","funny"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(13,'goal','Po rohovém kopu největší zmatek a {player} to tam nějak dostal.','["messy"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(14,'goal','{player} přebírá dlouhý nákop, otáčí se a pálí! Gól!','["long_ball"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(15,'goal','{player} překonává brankáře po zemi. Čistá práce.','["normal"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(16,'goal','Lobík od {player} přes vyběhnutého brankáře — nádherný gól!','["epic"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(17,'goal','{player} se prosadil v šestnáctce. Kolem něj byli tři obránci, ale stejně dal gól.','["epic"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(18,'goal','Gól po rychlém protiútoku! {player} to zakončil na první dotek.','["normal"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(19,'goal','{player} přiměl brankáře k chybě a uklidil to do sítě. Chytrý gól.','["normal"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(20,'goal','Dělovka od {player}! Brankář ani nehnul rukama. To letělo jak z praku.','["epic"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(21,'goal','{player} se dostal k odraženému míči a napálil to pod břevno!','["normal"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(22,'goal','Nečekaná střela {player} z třiceti metrů — a je to tam! {crowd_reaction}','["epic"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(23,'goal','{player} prostrčil míč mezi nohama obránci a pak i brankáři. Parádička!','["epic","funny"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(24,'goal','Míč se odrazil od tyče zpátky do hry, {player} na dorážku — gól!','["normal"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(25,'goal','{player} to tam prostě hodil. Nic hezkého, ale funguje to.','["ugly"]',0,'2026-03-28 21:33:10');
