INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(131,'special','{team} pomalu budují útok. Trpělivá hra.','["possession"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(132,'special','{player} nahrává do středu — míč se vrací do obrany.','["possession"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(133,'special','Rozehrávka od brankáře. {team} začínají znovu.','["possession"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(134,'special','{team} tlačí dopředu. Obrana soupeře má plné ruce práce.','["possession"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(135,'special','{player} se snaží projít přes dva hráče. Neúspěšně.','["possession"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(136,'special','Krátká nahrávka {player} na spoluhráče. Tempo se zrychluje.','["possession"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(137,'special','{team} drží míč. Soupeř čeká na chybu.','["possession"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(138,'special','Centr od {player} — nikdo se k němu nedostal.','["possession"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(139,'special','{player} posílá míč na druhou stranu. Přepínání hry.','["possession"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(140,'special','{team} se snaží najít mezeru v obraně.','["possession"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(141,'special','{player} si zpracoval míč na hrudi a hledá řešení.','["possession"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(142,'special','{team} rotují míč ze strany na stranu. Soupeř běhá.','["possession"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(143,'special','{player} přihrává do běhu spoluhráči. Dobré načasování.','["possession"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(144,'special','Aut pro {team}. Chvíle na vydechnutí.','["possession"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(145,'special','{player} si stáhl míč patičkou. Pak ale ztratil přehled.','["possession"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(146,'special','{team} se snaží zrychlit. Zatím marně.','["possession"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(147,'special','Rohový kop pro {team}. Všichni běží do vápna.','["possession"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(148,'special','{player} odkopává z vlastní šestnáctky. Trochu panika.','["possession"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(149,'special','Nudný pasáž hry. Ani jedna strana nechce riskovat.','["possession"]',0,'2026-03-28 21:33:10');
INSERT INTO "commentary_templates" ("id","event_type","template","tags","min_skill","created_at") VALUES(150,'special','{team} hrají na jistotu. Míč koluje v obraně.','["possession"]',0,'2026-03-28 21:33:10');
INSERT INTO "crowd_reactions" ("id","text") VALUES(1,'Na tribuně se zvedla vlna nadšení — tedy oba dva diváci.');
INSERT INTO "crowd_reactions" ("id","text") VALUES(2,'Místní chlapi u piva přestali na chvíli řešit politiku.');
INSERT INTO "crowd_reactions" ("id","text") VALUES(3,'Děda Vašek se probudil a zeptal se, co se stalo.');
INSERT INTO "crowd_reactions" ("id","text") VALUES(4,'Paní Nováková zavolala z okna, ať nekřičí.');
INSERT INTO "crowd_reactions" ("id","text") VALUES(5,'Pes, co leží za brankou, zvedl hlavu.');
INSERT INTO "crowd_reactions" ("id","text") VALUES(6,'U stánku přestali točit párek v rohlíku.');
INSERT INTO "crowd_reactions" ("id","text") VALUES(7,'Na parkovišti někdo zatroubil.');
INSERT INTO "crowd_reactions" ("id","text") VALUES(8,'Šest diváků aplauduje, sedmý zapíná mobil na video.');
INSERT INTO "crowd_reactions" ("id","text") VALUES(9,'Starosta se usmívá — investice do trávníku se vyplatila.');
INSERT INTO "crowd_reactions" ("id","text") VALUES(10,'Hospodský za plotem přinesl pivo pro gólmana.');
INSERT INTO "crowd_reactions" ("id","text") VALUES(11,'Kluk na kole za brankou spadl z kola nadšením.');
INSERT INTO "crowd_reactions" ("id","text") VALUES(12,'Důchodci na lavičce konečně odložili křížovku.');
INSERT INTO "crowd_reactions" ("id","text") VALUES(13,'Z okna protějšího baráku někdo vyhodil konfety. Tedy spíš zbytky oběda.');
INSERT INTO "crowd_reactions" ("id","text") VALUES(14,'Kočka, co sedí na střídačce, se lekla.');
INSERT INTO "crowd_reactions" ("id","text") VALUES(15,'U plotu propukla debata, jestli to byl ofsajd.');
INSERT INTO "crowd_reactions" ("id","text") VALUES(16,'Hasič, co jel kolem, zastavil se podívat.');
INSERT INTO "crowd_reactions" ("id","text") VALUES(17,'Tleskání a cinkání půllitrů — to je zvuk okresního fotbalu.');
INSERT INTO "crowd_reactions" ("id","text") VALUES(18,'Prodavačka z obchodu naproti vyběhla ven.');
INSERT INTO "crowd_reactions" ("id","text") VALUES(19,'Starý hasič vedle hřiště spustil sirénu. Prý omylem.');
INSERT INTO "crowd_reactions" ("id","text") VALUES(20,'Sousedovic kluk přestal házet míčem o zeď a konečně se dívá.');
INSERT INTO "crowd_reactions" ("id","text") VALUES(21,'Maminka jednoho hráče zakřičela: ''Tak to byl můj syn!''');
INSERT INTO "crowd_reactions" ("id","text") VALUES(22,'Rozhodčí se tváří, že to viděl. Neviděl.');
INSERT INTO "crowd_reactions" ("id","text") VALUES(23,'Na střídačce spadla láhev minerálky. Větší vzrušení než celý poločas.');
INSERT INTO "crowd_reactions" ("id","text") VALUES(24,'Dva diváci se začali hádat, kdo dal gól. Třetí říká, že to byl vlastňák.');
INSERT INTO "crowd_reactions" ("id","text") VALUES(25,'Z vedlejšího hřiště přiběhly děti — prý tu je to lepší.');
INSERT INTO "crowd_reactions" ("id","text") VALUES(26,'Chlap s trakařem se zastavil u plotu. Prý jen na chvíli. Stojí tam už půl hodiny.');
INSERT INTO "crowd_reactions" ("id","text") VALUES(27,'Krávy na louce vedle hřiště přestaly žvýkat.');
INSERT INTO "crowd_reactions" ("id","text") VALUES(28,'Někdo pustil rádio s hymnou. Nikdo neví proč.');
INSERT INTO "crowd_reactions" ("id","text") VALUES(29,'Babička s nákupní taškou se zastavila: ''Co to hrajete? Volejbal?''');
INSERT INTO "crowd_reactions" ("id","text") VALUES(30,'Holubi na střeše kabin se rozletěli.');
